+/// Determine whether an environment variable is safe to expose to extensions.
+///
+/// Uses a blocklist approach: most vars are allowed, but known sensitive
+/// patterns (API keys, secrets, tokens, passwords, credentials) are blocked.
+pub fn is_env_var_allowed(key: &str) -> bool {
+    const BLOCKED_EXACT: &[&str] = &[
+        "ANTHROPIC_API_KEY",
+        "OPENAI_API_KEY",
+        "GOOGLE_API_KEY",
+        "AZURE_OPENAI_API_KEY",
+        "COHERE_API_KEY",
+        "GROQ_API_KEY",
+        "DEEPINFRA_API_KEY",
+        "CEREBRAS_API_KEY",
+        "OPENROUTER_API_KEY",
+        "MISTRAL_API_KEY",
+        "MOONSHOT_API_KEY",
+        "DASHSCOPE_API_KEY",
+        "DEEPSEEK_API_KEY",
+        "FIREWORKS_API_KEY",
+        "TOGETHER_API_KEY",
+        "PERPLEXITY_API_KEY",
+        "XAI_API_KEY",
+        "DATABASE_URL",
+        "REDIS_URL",
+        "MONGODB_URI",
+        "PRIVATE_KEY",
+        "CARGO_REGISTRY_TOKEN",
+        "NPM_TOKEN",
+        "GH_TOKEN",
+        "GITHUB_TOKEN",
+    ];
+    const BLOCKED_SUFFIXES: &[&str] = &[
+        "_SECRET",
+        "_SECRET_KEY",
+        "_ACCESS_KEY",
+        "_PRIVATE_KEY",
+        "_PASSWORD",
+        "_PASSWD",
+        "_CREDENTIAL",
+        "_CREDENTIALS",
+    ];
+    const BLOCKED_PREFIXES: &[&str] = &["AWS_SECRET_", "AWS_SESSION_"];
+
+    if key.starts_with("PI_") {
+        return true;
+    }
+    if BLOCKED_EXACT.contains(&key) {
+        return false;
+    }
+    let upper = key.to_ascii_uppercase();
+    for suffix in BLOCKED_SUFFIXES {
+        if upper.ends_with(suffix) {
+            return false;
+        }
+    }
+    for prefix in BLOCKED_PREFIXES {
+        if upper.starts_with(prefix) {
+            return false;
+        }
+    }
+    true
+}
